void processRefund(RefundRequest refundRequest) {
    validateRefundRequestIsEligible(refundRequest);
    Order originalOrder = orderRepository.findById(refundRequest.getOriginalOrderId())
        .orElseThrow(() -> new OrderNotFoundException(refundRequest.getOriginalOrderId()));
    validateRefundAmountDoesNotExceedOriginalOrderTotal(refundRequest, originalOrder);
    Payment originalPayment = paymentRepository.findByOrderId(originalOrder.getId())
        .orElseThrow(() -> new PaymentNotFoundException(originalOrder.getId()));
    RefundTransaction refundTransaction = paymentGateway.processRefund(
        originalPayment.getTransactionId(),
        refundRequest.getRefundAmount());
    originalOrder.recordRefund(refundRequest.getRefundAmount(), refundTransaction.getId());
    orderRepository.save(originalOrder);
    refundRepository.save(buildRefundRecord(refundRequest, refundTransaction));
    notificationService.sendRefundConfirmationToCustomer(
        originalOrder.getCustomer(),
        refundRequest.getRefundAmount());
}
